using System;

class Box<T>
{
    private T item;

    public void Add(T value)
    {
        item = value;
    }

    public T Get()
    {
        return item;
    }
}

class Program
{
    static void Main(string[] args)
    {
        Box<int> numberBox = new Box<int>();
        numberBox.Add(42);
        Console.WriteLine($"Rəqəm qutusu: {numberBox.Get()}");

        Box<string> stringBox = new Box<string>();
        stringBox.Add("Salam");
        Console.WriteLine($"Sətir qutusu: {stringBox.Get()}");
    }
}
// Output:
// Rəqəm qutusu: 42
// Sətir qutusu: Salam

using System;

class Program
{
    static void Swap<T>(ref T first, ref T second)
    {
        T temp = first;
        first = second;
        second = temp;
    }

    static void Main(string[] args)
    {
        int a = 5, b = 10;
        Console.WriteLine($"Əvvəl: a = {a}, b = {b}");
        Swap(ref a, ref b);
        Console.WriteLine($"Sonra: a = {a}, b = {b}");

        string x = "Salam", y = "Dünya";
        Console.WriteLine($"\nƏvvəl: x = {x}, y = {y}");
        Swap(ref x, ref y);
        Console.WriteLine($"Sonra: x = {x}, y = {y}");
    }
}
// Output:
// Əvvəl: a = 5, b = 10
// Sonra: a = 10, b = 5
//
// Əvvəl: x = Salam, y = Dünya
// Sonra: x = Dünya, y = Salam

using System;

class Printer<T> where T : class
{
    public void Print(T item)
    {
        if (item != null)
        {
            Console.WriteLine($"Element: {item}");
        }
        else
        {
            Console.WriteLine("Element null-dır.");
        }
    }
}

class Program
{
    static void Main(string[] args)
    {
        Printer<string> stringPrinter = new Printer<string>();
        stringPrinter.Print("Salam");
        stringPrinter.Print(null);

        // Printer<int> numberPrinter = new Printer<int>(); // Kompilyator xətası: int sinif deyil
    }
}
// Output:
// Element: Salam
// Element null-dır.

using System;
using System.Collections;

class Program
{
    static void Main(string[] args)
    {
        ArrayList list = new ArrayList();
        list.Add(10);
        list.Add("sətir"); // Tip təhlükəsizliyi yoxdur

        try
        {
            int sum = 0;
            foreach (int number in list) // Səhv: Sətir ədədə çevrilə bilməz
            {
                sum += number;
            }
            Console.WriteLine($"Cəm: {sum}");
        }
        catch (InvalidCastException ex)
        {
            Console.WriteLine("Səhv: Tip çevrilməsi uğursuz oldu!");
            Console.WriteLine($"Səhv mesajı: {ex.Message}");
        }
    }
}
// Output:
// Səhv: Tip çevrilməsi uğursuz oldu!
// Səhv mesajı: Specified cast is not valid.

