using System;
using System.Collections;

class Program
{
    static void Main(string[] args)
    {
        ArrayList list = new ArrayList();
        list.Add(10);
        list.Add("string"); // No type safety

        try
        {
            int sum = 0;
            foreach (int number in list) // Error: String cannot be cast to int
            {
                sum += number;
            }
            Console.WriteLine($"Sum: {sum}");
        }
        catch (InvalidCastException ex)
        {
            Console.WriteLine("Error: Type casting failed!");
            Console.WriteLine($"Error message: {ex.Message}");
        }
    }
}
// Output:
// Error: Type casting failed!
// Error message: Specified cast is not valid.

